import jwt from 'jsonwebtoken';
import jwksClient from 'jwks-rsa';
import { DynamoDBClient, ScanCommand } from '@aws-sdk/client-dynamodb';

// Structured logger (2.2) - inline since this Lambda does not use admin-auth layer
const _LL = { DEBUG: 0, INFO: 1, WARN: 2, ERROR: 3 };
const _ML = _LL[(process.env.LOG_LEVEL || 'INFO').toUpperCase()] ?? 1;
const _createLogger = (svc) => {
  let _pk = {};
  const _l = (lvl, msg, ex = {}) => {
    if ((_LL[lvl] ?? 0) >= _ML) {
      const extra = (typeof ex === 'object' && ex !== null && !(ex instanceof Error)) ? ex : { detail: String(ex) };
      console.log(JSON.stringify({ timestamp: new Date().toISOString(), level: lvl, service: svc, message: msg, ..._pk, ...extra }));
    }
  };
  return {
    info: (m, e) => _l('INFO', m, e),
    warn: (m, e) => _l('WARN', m, e),
    error: (m, e) => _l('ERROR', m, e),
    debug: (m, e) => _l('DEBUG', m, e),
    appendKeys: (k) => { _pk = { ..._pk, ...k }; },
    resetKeys: () => { _pk = {}; },
  };
};
const logger = _createLogger('multi-tenant-authorizer');

/**
 * Multi-tenant Lambda authorizer for API Gateway
 * Validates JWT tokens from multiple Cognito User Pools
 *
 * OPTIMIZATION (1.2): O(1) tenant lookup via JWT issuer extraction
 * ================================================================
 * Previously, this authorizer tried to verify the JWT against ALL tenant
 * UserPools in parallel (O(N) complexity). With 100+ tenants, this caused
 * excessive JWKS requests and potential cold-start timeouts.
 *
 * Now we:
 * 1. Decode the JWT (without verification) to extract the `iss` (issuer) claim
 * 2. The issuer contains the UserPool ID: "https://cognito-idp.{region}.amazonaws.com/{userPoolId}"
 * 3. Look up the matching tenant from the cached tenant list — O(1) via Map
 * 4. Verify the JWT only against the matched tenant's UserPool — single verification
 *
 * This reduces verification from O(N) to O(1) regardless of tenant count.
 */

// Cache for JWKS clients to avoid repeated requests
const jwksClients = new Map();

// Cache for tenant data from DynamoDB
let tenantsCache = null;
// Reverse index: userPoolId → tenant data (for O(1) lookup)
let tenantsByUserPoolId = null;
let tenantsCacheTimestamp = 0;
const TENANTS_CACHE_TTL = 5 * 60 * 1000; // 5 minutes

const dynamodb = new DynamoDBClient({ region: process.env.AWS_REGION || 'us-east-1' });

/**
 * Load tenant data from DynamoDB (with caching)
 * Also builds a reverse index: userPoolId → tenant for O(1) lookup
 */
async function loadTenantsData() {
    const now = Date.now();
    if (tenantsCache && tenantsByUserPoolId && (now - tenantsCacheTimestamp) < TENANTS_CACHE_TTL) {
        return { tenants: tenantsCache, byUserPoolId: tenantsByUserPoolId };
    }

    const tableName = process.env.TENANT_TABLE || 'amfa-tenanttable';

    const result = await dynamodb.send(new ScanCommand({
        TableName: tableName,
        FilterExpression: 'begins_with(id, :prefix)',
        ExpressionAttributeValues: {
            ':prefix': { S: 'TENANT#' }
        },
        ProjectionExpression: 'id, userpool, spPortalClientId'
    }));

    const tenants = (result.Items || []).map(item => ({
        tenantId: item.id?.S?.replace('TENANT#', ''),
        userPoolId: item.userpool?.S,
        spPortalClientId: item.spPortalClientId?.S,
    })).filter(t => t.userPoolId && t.spPortalClientId);

    // Build reverse index: userPoolId → tenant
    const byUserPoolId = new Map();
    for (const tenant of tenants) {
        byUserPoolId.set(tenant.userPoolId, tenant);
    }

    tenantsCache = tenants;
    tenantsByUserPoolId = byUserPoolId;
    tenantsCacheTimestamp = now;
    logger.info(`[Authorizer] Loaded ${tenants.length} tenant(s) from DynamoDB, indexed by userPoolId`);
    return { tenants, byUserPoolId };
}

/**
 * Get JWKS client for a specific user pool
 */
function getJwksClient(region, userPoolId) {
    const key = `${region}:${userPoolId}`;

    if (!jwksClients.has(key)) {
        const client = jwksClient({
            jwksUri: `https://cognito-idp.${region}.amazonaws.com/${userPoolId}/.well-known/jwks.json`,
            cache: true,
            cacheMaxEntries: 5,
            cacheMaxAge: 600000, // 10 minutes
        });
        jwksClients.set(key, client);
    }

    return jwksClients.get(key);
}

/**
 * Get signing key for JWT verification
 */
function getSigningKey(client, kid) {
    return new Promise((resolve, reject) => {
        client.getSigningKey(kid, (err, key) => {
            if (err) {
                reject(err);
            } else {
                resolve(key.getPublicKey());
            }
        });
    });
}

/**
 * Extract the UserPool ID from a JWT token's issuer claim.
 *
 * Cognito JWT issuer format: "https://cognito-idp.{region}.amazonaws.com/{userPoolId}"
 * We decode (without verification) to read the `iss` claim and extract the UserPool ID.
 *
 * Note: Decoding without verification is safe here because we only use the extracted
 * userPoolId to SELECT which public key to verify against. The actual cryptographic
 * verification happens in verifyToken(). An attacker cannot forge a valid signature
 * even if they manipulate the issuer claim.
 *
 * @param {string} token - Raw JWT token string
 * @returns {{ userPoolId: string, issuer: string } | null} Extracted info or null if invalid
 */
function extractIssuerInfo(token) {
    try {
        const decoded = jwt.decode(token, { complete: true });
        if (!decoded || !decoded.payload || !decoded.payload.iss) {
            return null;
        }

        const issuer = decoded.payload.iss;
        // Issuer format: https://cognito-idp.{region}.amazonaws.com/{userPoolId}
        const parts = issuer.split('/');
        const userPoolId = parts[parts.length - 1];

        if (!userPoolId || !userPoolId.includes('_')) {
            // Cognito UserPool IDs always contain underscore: {region}_{id}
            logger.info(`[Authorizer] Invalid userPoolId format in issuer: ${issuer}`);
            return null;
        }

        return { userPoolId, issuer };
    } catch (error) {
        logger.info(`[Authorizer] Failed to decode JWT for issuer extraction: ${error.message}`);
        return null;
    }
}

/**
 * Verify JWT token against a specific user pool
 */
async function verifyToken(token, region, userPoolId, clientId) {
    try {
        // Decode token header to get kid
        const decoded = jwt.decode(token, { complete: true });
        if (!decoded || !decoded.header || !decoded.header.kid) {
            throw new Error('Invalid token structure');
        }

        // Get JWKS client and signing key
        const client = getJwksClient(region, userPoolId);
        const signingKey = await getSigningKey(client, decoded.header.kid);

        // Verify token
        const payload = jwt.verify(token, signingKey, {
            algorithms: ['RS256'],
            audience: clientId,
            issuer: `https://cognito-idp.${region}.amazonaws.com/${userPoolId}`,
        });

        return {
            valid: true,
            payload,
            userPoolId,
            clientId
        };
    } catch (error) {
        logger.info(`[Authorizer] Token verification failed for pool ${userPoolId}: ${error.message}`);
        return {
            valid: false,
            error: error.message,
            userPoolId,
            clientId
        };
    }
}

/**
 * Extract tenant ID from various sources (fallback only)
 */
function extractTenantId(event, tokenPayload) {
    // Try to get tenant ID from headers first
    const headers = event.headers || {};
    const tenantIdHeader = headers['x-tenant-id'] || headers['X-Tenant-Id'];

    if (tenantIdHeader) {
        return tenantIdHeader;
    }

    // Try to extract from token payload (custom attributes)
    if (tokenPayload && tokenPayload['custom:tenant_id']) {
        return tokenPayload['custom:tenant_id'];
    }

    // Try to extract from username or email domain
    if (tokenPayload && tokenPayload.email) {
        const emailDomain = tokenPayload.email.split('@')[1];
        // This is a fallback - you might want to implement domain-to-tenant mapping
        return emailDomain.split('.')[0]; // Simple extraction, customize as needed
    }

    return null;
}

/**
 * Generate HTTP API v2 simple response format
 */
function generateResponse(isAuthorized, context = {}) {
    return {
        isAuthorized,
        context,
    };
}

/**
 * Main Lambda handler
 *
 * Flow (O(1) optimized):
 * 1. Extract JWT from Authorization header
 * 2. Decode JWT (no verification) to get issuer → userPoolId
 * 3. Look up tenant by userPoolId in cached Map → O(1)
 * 4. Verify JWT against the single matched tenant's UserPool
 * 5. Return authorized response with tenant context
 */
export const handler = async (event) => {
    logger.info('[Authorizer] Event received:', JSON.stringify({
        routeArn: event.routeArn,
        headers: event.headers ? Object.keys(event.headers) : [],
    }));

    try {
        // Extract token from Authorization header
        // HTTP API v2 uses event.headers.authorization, REST API v1 uses event.authorizationToken
        const token = event.headers?.authorization || event.authorizationToken;
        if (!token) {
            throw new Error('No authorization token provided');
        }

        // Remove 'Bearer ' prefix if present
        const cleanToken = token.replace(/^Bearer\s+/i, '');

        const region = process.env.AWS_REGION || 'us-east-1';

        // STEP 1: Extract issuer from JWT to identify the UserPool (O(1))
        const issuerInfo = extractIssuerInfo(cleanToken);
        if (!issuerInfo) {
            logger.info('[Authorizer] Could not extract issuer from JWT');
            throw new Error('Invalid token - could not extract issuer');
        }

        logger.info(`[Authorizer] Token issuer userPoolId: ${issuerInfo.userPoolId}`);

        // STEP 2: Load tenant data and look up by userPoolId (O(1) via Map)
        const { byUserPoolId } = await loadTenantsData();
        const matchedTenant = byUserPoolId.get(issuerInfo.userPoolId);

        if (!matchedTenant) {
            logger.info(`[Authorizer] No tenant found for userPoolId: ${issuerInfo.userPoolId}`);
            throw new Error('Unknown user pool - unauthorized');
        }

        logger.info(`[Authorizer] Matched tenant: ${matchedTenant.tenantId} (userPool: ${matchedTenant.userPoolId})`);

        // STEP 3: Verify JWT against the single matched tenant's UserPool (O(1))
        const result = await verifyToken(
            cleanToken,
            region,
            matchedTenant.userPoolId,
            matchedTenant.spPortalClientId
        );

        if (!result.valid) {
            logger.info(`[Authorizer] Token verification failed for tenant ${matchedTenant.tenantId}: ${result.error}`);
            throw new Error('Unauthorized');
        }

        logger.info(`[Authorizer] Token verified for tenant: ${matchedTenant.tenantId}`);

        // Use tenant ID from DDB match (most reliable), with header/token fallback
        const tenantId = matchedTenant.tenantId || extractTenantId(event, result.payload);

        // Generate HTTP API v2 simple response
        const response = generateResponse(true, {
            tenantId,
            userPoolId: result.userPoolId,
            clientId: result.clientId,
            username: result.payload.username || result.payload['cognito:username'],
            email: result.payload.email,
            groups: JSON.stringify(result.payload['cognito:groups'] || []),
        });

        logger.info('[Authorizer] Authorized:', JSON.stringify({ tenantId, username: response.context.username }));
        return response;

    } catch (error) {
        logger.error('[Authorizer] Authorization error:', error.message);

        // Return deny response
        return generateResponse(false, {
            error: error.message,
        });
    }
};
